export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "21:20。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "救護人員到了。兩個人。穿深藍色制服，戴手套，拎著急救箱和摺疊擔架。他們從通道入口側身擠進來，蹲在千田兩側。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Paramedic, character: "救護人員", dialogue: "有意識嗎？", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "半清醒。剛才還能說幾個字。呼吸很淺。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "救護人員剪開千田的外套。剪刀沿著縫線走，布料被扯開的聲音很輕，但在通道裡聽起來很尖銳。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在兩步之外。她在看。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯內袋。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外套被拉開的一瞬間。她的視線掃過千田的胸口——內袋的位置。那裡有一個硬的輪廓。薄的。長方形的。隔著被血浸透的襯衫布料，那個東西的邊緣頂著布面。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯還在。銀色外殼。還在他身上。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但救護人員的動作太快了。他們把外套從千田身上剝下來，翻過去，塞進一個透明的塑膠袋裡。整個過程不到五秒。澪的眼睛追著那件外套，追著那個透明的袋子——", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隔著透明塑膠。在外套被折起來的褶皺裡。一個薄而硬的輪廓。長方形。邊緣很硬。像一本很薄的書。又像一個金屬殼。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯在裡面。在衣物袋裡。跟著他的外套。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我想說。我想說那件東西很重要。不要把它當成普通衣物。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她張了一下嘴。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她閉上了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯說什麼？說我知道那是什麼？說那是悠真留下的東西？說那是上一輪千田塞給我的銀色外殼？", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我怎麼會知道一個受傷陌生人外套裡面藏了什麼？我非法進入限制區。我滿手是血。我說「那件東西很重要」——他們會問我為什麼知道。然後那件東西就會變成證物。進入官方流程。被封存。被登記。被送到某個我碰不到的地方。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯和千田一樣。被送進去。不代表安全。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她什麼都沒說。她看著那個透明的衣物袋被紮住袋口，掛在擔架側面的掛鉤上。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "救護人員把千田固定在擔架上。頸圈。固定帶。血壓計袖帶纏在他的上臂上，讀數她看不到，但救護人員交換了一個眼神。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Paramedic, character: "救護人員", dialogue: "血壓偏低。失血量不少。要快。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.StationStaff, character: "站務人員", dialogue: "先送往灣岸中央急救醫療中心。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的眼睛動了一下。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯灣岸中央急救醫療中心。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯記住。記住這個名字。這不是公開資訊。這是救護和站務之間的流程資訊。不會出現在車站廣播裡。不會出現在電子看板上。只有現在、在這裡、站在這個位置的人才聽得到。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯灣岸中央急救醫療中心。記住了。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "擔架被推出通道。站務員和保全拉開警戒帶讓路。救護人員推著擔架穿過月台後方的員工通道，往站外的救護車停靠區走。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪跟在後面。沒有人叫她停。也沒有人叫她跟上。她只是跟著。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "站外。夜風。灣岸道路的車燈在遠處流動。救護車的紅燈在旋轉，把地面上的水漬染成一圈一圈的紅色。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "擔架被推到救護車後門。救護人員把它抬起來，滑進車廂。千田的臉在擔架的白色床單上顯得很灰。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他的眼睛動了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "開了。半開。焦點不在救護人員身上。不在站務員身上。在澪身上。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在看她。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在看我。像在確認什麼。像在確認我聽到了沒有。確認我記住了沒有。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的嘴唇動了。很微弱。聲音幾乎被夜風和救護車引擎吞掉。但澪離得夠近。她聽見了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.ChidaKosuke, character: "千田浩介", dialogue: "別讓他們⋯⋯換成救援⋯⋯", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.ChidaKosuke_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他的眼睛閉上了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯別讓他們。換成救援。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯什麼意思？別讓誰把什麼換成救援？別讓他們把外殼換成救援流程的一部分？別讓他們把攻擊換成救援事故？", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他說不清楚。他沒有力氣說清楚了。但他在看我。他在確認我聽到了。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "救護車的後門關上了。金屬碰撞聲。很沉。很悶。像一個句號。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "引擎聲變大。車燈亮起來。救護車緩緩駛離站外停靠區，匯入灣岸道路的車流。紅色尾燈在夜色裡越來越小。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪站在原地。風吹過她的頭髮。她的手垂在身側。手指上的血已經開始乾了，變成暗褐色的薄殼，在風裡繃著她的皮膚。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她轉頭。月台方向。電子看板。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "綠色的字。在黑色的螢幕上。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第七車。21:40。準點抵達。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第七車。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第一輪。他在那裡。死在座位旁邊。血從外套下面滲出來。我拿著銀色外殼。系統把我標記成持尖銳物者。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯這一輪。他不會在那裡了。車廂裡不會有屍體。不會有血。不會有外殼。不會有那張把我困住的畫面。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯第七車裡沒有屍體了。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處。灣岸道路上。救護車的紅燈已經看不見了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯我救下了第七車裡的千田。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯但我沒有救下千田本人。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他只是換了一個地方。換了一輛車。換了一種被送進去的方式。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯外殼也一樣。不在他身上——不在我的手上——在衣物袋裡。跟著他。去同一個地方。", background: Background.Chapter_6_Ch6_Act6_S0, portrait: Portrait.AsakuraMio_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在站外。看著電子看板上「第七車」三個字慢慢滾動，被下一班車的資訊擠走。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第一輪的死亡畫面已經沒有了。", background: Background.Chapter_6_Ch6_Act6_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但千田還在流血。只是不在第七車裡了。", background: Background.Chapter_6_Ch6_Act6_S0 },
];
